import{_ as o,o as t,c as i,a2 as u}from"./chunks/framework.c6mn6h8d.js";const p=JSON.parse('{"title":"附录：面试高频开放题参考回答","description":"","frontmatter":{"title":"附录：面试高频开放题参考回答"},"headers":[],"relativePath":"appendix-open-questions.md","filePath":"appendix-open-questions.md","lastUpdated":null}'),a={name:"appendix-open-questions.md"};function r(e,l,n,s,q,g){return t(),i("div",null,[...l[0]||(l[0]=[u('<h1 id="附录-面试高频开放题参考回答" tabindex="-1">附录：面试高频开放题参考回答 <a class="header-anchor" href="#附录-面试高频开放题参考回答" aria-label="Permalink to &quot;附录：面试高频开放题参考回答&quot;">​</a></h1><h3 id="请介绍一下你在ai方面的项目经验。" tabindex="-1">&quot;请介绍一下你在AI方面的项目经验。&quot; <a class="header-anchor" href="#请介绍一下你在ai方面的项目经验。" aria-label="Permalink to &quot;&quot;请介绍一下你在AI方面的项目经验。&quot;&quot;">​</a></h3><blockquote><p>我在上海易碳数字科技有限公司（积木LCA云平台）担任开发负责人，负责AI相关的技术方向。公司专注于工业制造业碳排放数据量化云计算，服务冶金、建材、化工等流程制造企业。</p><p>我主导的核心项目是<strong>碳管家AI助手</strong>——一个基于 RAG 的碳管理智能问答系统。用户（企业碳管理人员）可以通过自然语言查询碳法规（如 CBAM）、ISO 标准（如 ISO 14067）、碳排放因子等专业问题。</p><p>技术栈是 Spring Boot 3 + Spring AI + LangChain4j + Milvus + Redis，大模型使用通义千问。知识库涵盖数万份碳管理专业文档，通过 RAG 实现知识增强。</p><p>我负责整体架构设计、RAG 流水线搭建、多模型集成、性能优化（语义缓存、Re-ranking、模型分级），将检索准确率从 75% 提升到 92%，API 成本降低 60%。同时管理5人开发团队。</p></blockquote><h4 id="追问" tabindex="-1">追问： <a class="header-anchor" href="#追问" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你说检索准确率从 75% 提升到 92%，这个 92% 是用什么评测集、由谁标注、人工评测还是自动评测得出的？评测样本量有多大？ <ul><li><strong>答</strong>：通常用内部人工标注的评测集，不做自动拍脑袋。 <ul><li>从真实用户 query 中抽样（例如 200~500 条），由碳领域专家或我本人标注&quot;标准答案/相关文档&quot;。</li><li>准确率定义为&quot;检索 Top-K 命中标准答案文档&quot;的比例，自动计算 + 人工抽检复核。</li><li>垂直领域无公开 benchmark，评测集均为内部自建，口径在迭代中保持一致。</li></ul></li></ul></li><li>追问2：通义千问在碳法规问答上出现过幻觉吗？你用的具体是 qwen-max 还是 qwen-plus，为什么不选 GPT-4 或 Claude？ <ul><li><strong>答</strong>：出现过，靠引用约束 + 置信度阈值兜底。 <ul><li>用的是通义千问系列（qwen-plus / qwen-max，具体版本按当时选型）。</li><li>选它主要考虑：中文法规语料更友好、碳数据合规不出境、API 成本低于 GPT-4/Claude。</li><li>幻觉通过 System Prompt 强制引用来源、低置信度时拒答来抑制。</li></ul></li></ul></li><li>追问3：5 人团队里你具体写了多少代码？碳管家 AI 助手的核心模块有几成是你独立完成的，几成是团队做的？ <ul><li><strong>答</strong>：架构、RAG 流水线、性能优化由我主导落地，业务模块团队分工。 <ul><li>我负责整体架构及检索/重排/缓存等核心链路的设计与关键代码，约占核心模块 6~7 成。</li><li>团队负责文档解析、前端联调、知识库运营，我做 code review 与技术把关。</li><li>体量不大，我既是架构师也是主要 contributor。</li></ul></li></ul></li></ul><h3 id="你遇到的最大技术挑战是什么" tabindex="-1">&quot;你遇到的最大技术挑战是什么？&quot; <a class="header-anchor" href="#你遇到的最大技术挑战是什么" aria-label="Permalink to &quot;&quot;你遇到的最大技术挑战是什么？&quot;&quot;">​</a></h3><blockquote><p>最大的挑战是 RAG 检索准确率。碳管理领域对准确性要求极高——法规条款不能有偏差，碳排放数据必须精确。初期检索准确率只有 75%，用户经常得到不相关或错误的信息。</p><p>我从三个层面优化：</p><ol><li><strong>检索层</strong>：增加 Re-ranking（bge-reranker），从 Top-20 精排到 Top-5。</li><li><strong>分块层</strong>：从固定长度分块改为按标准章节语义分块，保持条款完整性。</li><li><strong>Prompt 层</strong>：强化 System Prompt 约束，要求引用来源，设置置信度阈值。</li></ol><p>最终准确率提升到 92%，用户满意度从 3.5 提升到 4.3（满分5）。</p></blockquote><h4 id="追问-1" tabindex="-1">追问： <a class="header-anchor" href="#追问-1" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你说从固定长度分块改成按标准章节语义分块，那 Java 后端怎么识别&quot;章节边界&quot;？是规则解析还是模型切分，准确率如何保证不把条款切坏？ <ul><li><strong>答</strong>：规则解析为主，结合文档结构特征。 <ul><li>碳法规 PDF/Word 有固定层级（章/节/条/款），按标题样式、编号正则（如&quot;第X条&quot;）切分。</li><li>切分后做完整性校验：条款含结尾词才算完整，否则合并相邻块。</li><li>关键是不按字符数硬截断，保证条款原子性不被切坏。</li></ul></li></ul></li><li>追问2：bge-reranker 是本地部署还是调用 API？Top-20 到 Top-5 的精排，有没有出现过正确答案被排到 5 名之后被丢弃的情况，你怎么兜底？ <ul><li><strong>答</strong>：建议本地部署（ONNX / TorchServe），避免 API 延迟与成本。 <ul><li>兜底：召回保留 Top-20，精排只用于展示/生成；生成阶段仍允许引用 Top-20 范围。</li><li>设分数阈值，低于阈值不进生成；或&quot;重排 Top-5 但保留 Top-10 上下文&quot;策略。</li><li>监控被排到 5 名之后的答案命中率，定期回灌评测集。</li></ul></li></ul></li><li>追问3：准确率 75% 到 92% 这是上线前还是上线后的数据？用户满意度 3.5 到 4.3 是基于多少份真实用户反馈，还是你自己的主观判断？ <ul><li><strong>答</strong>：92% 是上线前离线评测集结果，也是上线后持续监控的基线。 <ul><li>满意度 3.5→4.3 来自真实用户反馈（如数百条问卷/NPS 或拦截调研，具体样本量可说明）。</li><li>上线后用埋点采集&quot;是否解决问题&quot;的点赞/点踩，持续验证不靠主观判断。</li></ul></li></ul></li></ul><h3 id="你对ai技术未来发展的看法" tabindex="-1">&quot;你对AI技术未来发展的看法？&quot; <a class="header-anchor" href="#你对ai技术未来发展的看法" aria-label="Permalink to &quot;&quot;你对AI技术未来发展的看法？&quot;&quot;">​</a></h3><blockquote><p>我认为 AI 工程化的核心挑战不在于模型本身（模型越来越强），而在于如何将模型能力可靠、高效、低成本地落地到业务场景。</p><p>三个趋势我特别关注：</p><ol><li><strong>Agent 自主化</strong>：从被动问答到主动执行任务。</li><li><strong>MCP 标准化</strong>：工具调用标准化，实现跨平台复用。</li><li><strong>成本持续下降</strong>：模型推理成本快速下降，更多场景变得经济可行。</li></ol><p>作为 Java 后端工程师，我的定位是&quot;AI 工程化专家&quot;——把强大的模型能力，通过扎实的工程能力落地到企业业务中。</p></blockquote><h4 id="追问-2" tabindex="-1">追问： <a class="header-anchor" href="#追问-2" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你说 Agent 会&quot;从被动问答到主动执行任务&quot;，那在碳管理这个合规强约束场景里，Agent 主动执行出错谁担责？你打算怎么设计它的安全边界？ <ul><li><strong>答</strong>：强合规场景下 Agent 只做&quot;建议&quot;，不自动执行不可逆操作。 <ul><li>安全边界：高风险的写/提交/对外发送必须人工确认（human-in-the-loop）。</li><li>操作留痕、可回滚，权限按角色最小化，关键动作加二次校验。</li><li>责任划分：人工确认后的执行由操作人担责，系统只提供基于证据的建议。</li></ul></li></ul></li><li>追问2：你提 MCP 标准化，但你们现在 LangChain4j + Spring AI 两套框架并存，是不是本身架构就没统一好？MCP 能解决你当前的什么问题？ <ul><li><strong>答</strong>：并存是历史演进与选型验证，不是架构混乱。 <ul><li>Spring AI 对接标准化 Chat/embedding 接口，LangChain4j 用于部分链编排，逐步收敛到统一抽象层。</li><li>MCP 价值在于把&quot;工具调用&quot;标准化，未来 Agent 的工具（查因子、算排放）可跨框架复用，减少重复封装。</li></ul></li></ul></li><li>追问3：你说&quot;成本持续下降所以更多场景可行&quot;，可你前面又说靠语义缓存和模型分级把 API 成本降了 60%，这不说明现在成本仍是核心瓶颈吗？ <ul><li><strong>答</strong>：两说法不矛盾——成本是相对瓶颈，靠工程手段在当下压住。 <ul><li>模型分级（简单问题小模型）+ 语义缓存复用，是针对&quot;当前成本仍高&quot;的务实优化。</li><li>&quot;成本持续下降&quot;是长期趋势，意味着现在值得投入的优化未来 ROI 更高，二者是&quot;现状优化 + 趋势判断&quot;。</li></ul></li></ul></li></ul><h3 id="你为什么想离开现在的公司" tabindex="-1">&quot;你为什么想离开现在的公司？&quot; <a class="header-anchor" href="#你为什么想离开现在的公司" aria-label="Permalink to &quot;&quot;你为什么想离开现在的公司？&quot;&quot;">​</a></h3><blockquote><p>这是个很自然的选择。在易碳这 3 年多，我从 0 到 1 搭建了碳管家 AI 助手，把 RAG 检索准确率从 75% 做到 92%，团队也从我 1 个人带到现在 5 个人。公司在碳管理垂直领域做得不错，但我想追求更大的技术挑战——</p><p>一是<strong>技术广度</strong>：现在更多是 RAG + 智能问答，我希望接触到更大规模的模型推理平台、更复杂的 Agent 编排、多模态场景；二是<strong>业务规模</strong>：碳管理是垂直领域，我想到用户量更大、并发更高的平台去验证自己架构设计的能力；三是<strong>成长环境</strong>：我希望能加入技术氛围更浓、有资深前辈能带我的团队。</p><p>我不是冲动跳槽，是希望找到一个能让我接下来 3-5 年持续成长的地方。</p></blockquote><h4 id="追问-3" tabindex="-1">追问： <a class="header-anchor" href="#追问-3" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你说想去&quot;用户量更大、并发更高&quot;的平台验证架构能力，但碳管家现在的 QPS 大概多少？你到底有没有扛过真正的高并发系统，还是只在垂直小场景里？ <ul><li><strong>答</strong>：碳管家是 B 端工具，QPS 不高（例如日常几十、峰值数百），非 C 端高并发。 <ul><li>高并发经验来自架构设计：Redis 语义缓存、RabbitMQ 异步削峰、K8s 弹性扩容、虚拟线程处理 IO 密集。</li><li>我坦诚这是垂直场景，正因此想去找更大规模平台验证——这也是求职动机之一。</li></ul></li></ul></li><li>追问2：你说想有资深前辈带，那在易碳 3 年你作为开发负责人，你的技术决策有没有被挑战或推翻过？举一个你承认当时设计错的例子。 <ul><li><strong>答</strong>：有过。早期我把知识库按固定 512 token 切分，结果长条款被截断、召回差。 <ul><li>被团队和领域专家质疑后，我改为按标准章节语义分块，准确率明显提升。</li><li>我的习惯是评测驱动、用数据说话，错了就快速迭代。</li></ul></li></ul></li><li>追问3：你说&quot;不是冲动跳槽&quot;，但为什么是现在这个时间点？是项目做完了没挑战了，还是公司层面有什么变化？ <ul><li><strong>答</strong>：主要是个人成长节奏到节点，不是被动离开。 <ul><li>碳管家从 0 到 1 已跑通、团队成型，我在这块技术挑战边际递减。</li><li>同时希望接触更大规模推理平台和 Agent 编排，时间上正好衔接。</li></ul></li></ul></li></ul><h3 id="你的薪资期望是多少" tabindex="-1">&quot;你的薪资期望是多少？&quot; <a class="header-anchor" href="#你的薪资期望是多少" aria-label="Permalink to &quot;&quot;你的薪资期望是多少？&quot;&quot;">​</a></h3><blockquote><p>基于我了解到的情况，结合我 5 年 Java 后端 + 3 年 AI 工程化的经验，以及开发负责人的管理经历，我的期望是 <strong>XX 万 × 16 薪</strong>左右，具体可以根据岗位职责和整体 package 来谈。</p><p>我更看重的是平台和成长空间，薪资在合理范围内我都可以接受。如果贵司有期权或其他长期激励，base 可以再商量。我也理解每个公司有自己的薪资结构，我愿意配合。</p></blockquote><blockquote><p><strong>话术要点</strong>：① 给区间而非死数；② 留谈判空间（说&quot;左右&quot;）；③ 强调看重成长而非只看钱；④ 主动提长期激励可替代 base，显得务实。</p></blockquote><h4 id="追问-4" tabindex="-1">追问： <a class="header-anchor" href="#追问-4" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你说期望&quot;XX 万 × 16 薪&quot;，那真实的底价是多高？如果我们要你接受 12 薪，base 上浮多少你能接受？ <ul><li><strong>答</strong>：XX 是占位，真实面试会给可谈的底线区间。 <ul><li>若改 12 薪，总包不变则 base 需上浮约 (16-12)/12 ≈ 33% 补齐。</li><li>我以总包（base×月数 + 奖金/期权）为锚谈判，而非只看月数。</li></ul></li></ul></li><li>追问2：你说&quot;在合理范围内都可以接受&quot;，那你的合理范围上限和下限分别是多少？请用数字说，不要再用区间话术。 <ul><li><strong>答</strong>：会基于市场行情和当前总包给明确数字（例如下限 A 万、上限 B 万总包）。 <ul><li>文档用占位 XX 是模板，真实面试需按岗位 JD 和自身情况填数。</li><li>下限是&quot;低于则不值得跳&quot;，上限是&quot;理想目标&quot;，中间可谈。</li></ul></li></ul></li><li>追问3：你之前管理 5 人团队，如果新岗位是纯个人贡献者（不带人），薪资不变你还会来吗？ <ul><li><strong>答</strong>：看成长性和技术挑战，不只看是否带人。 <ul><li>若技术栈更前沿、能接触更大规模系统，纯 IC 我也愿意，管理不是唯一诉求。</li><li>但薪资不变 + 明显降维的工作量，我会重新评估——坦诚而非硬撑。</li></ul></li></ul></li></ul><h3 id="你还有什么想问我们的吗-反问环节" tabindex="-1">&quot;你还有什么想问我们的吗？&quot;（反问环节） <a class="header-anchor" href="#你还有什么想问我们的吗-反问环节" aria-label="Permalink to &quot;&quot;你还有什么想问我们的吗？&quot;（反问环节）&quot;">​</a></h3><blockquote><p>我准备了几个问题，想请教一下：</p><ol><li><strong>团队现状</strong>：我入职后会加入哪个团队？团队规模多大？目前最核心的项目是什么？</li><li><strong>技术栈与架构</strong>：团队目前用的大模型主要是什么？推理是自建还是调用云 API？有没有自建向量库和 RAG 平台？</li><li><strong>业务方向</strong>：这个岗位未来半年的核心目标是什么？是偏新业务搭建，还是现有系统优化？</li><li><strong>成长路径</strong>：团队里有没有资深的技术 leader？入职后大概多久能独立负责一块业务？</li><li><strong>协作方式</strong>：产品和研发的协作流程是怎样的？发版节奏大概多快？</li></ol></blockquote><blockquote><p><strong>反问的目的</strong>：① 展示你对岗位的认真思考；② 借机判断团队是否值得加入（避免踩坑）；③ 体现技术视野（问技术栈和架构显得专业）。<strong>不要问薪资福利、加班时间</strong>——这些留到 HR 环节问。</p></blockquote><h4 id="追问-5" tabindex="-1">追问： <a class="header-anchor" href="#追问-5" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你问了技术栈、团队规模、业务方向，却没问你们这个 AI 岗位 KPI 怎么定、失败怎么算——是没想到，还是故意避开不好答的？ <ul><li><strong>答</strong>：不是故意避开，而是把&quot;如何定义成功&quot;融进了业务方向问题里。 <ul><li>更好做法是单独问 KPI/验收标准，能判断岗位是否结果导向、容错空间多大。</li><li>我会补一句：这个岗位半年内的成功标准怎么定、失败如何界定？</li></ul></li></ul></li><li>追问2：你准备了 5 个反问，但如果我告诉你团队目前没有资深技术 leader、且发版节奏是半年一次，你还愿意来吗？ <ul><li><strong>答</strong>：取决于我加入的价值——若正是我去搭建技术体系、节奏慢但能做深，反而有机会。 <ul><li>若既无资深可学、又无挑战，只是维护存量，那和长期成长目标冲突，我会谨慎。</li><li>我会再追问&quot;为什么半年一次&quot;&quot;技术决策谁拍板&quot;来判断。</li></ul></li></ul></li><li>追问3：你这些反问更像背模板，有没有一个问题是你基于自己真实顾虑、而不是&quot;显得专业&quot;才问的？ <ul><li><strong>答</strong>：我真实顾虑是&quot;有没有资深技术 leader 能带我&quot;和&quot;成长路径&quot;。 <ul><li>这两点直接关系未来 3 年成长，我会明确说这是我最在意的，不是显得专业。</li><li>其余问题是为判断团队值不值得加入，属理性尽调，不算无意义模板。</li></ul></li></ul></li></ul><h3 id="相比其他候选人-你觉得你的优势是什么" tabindex="-1">&quot;相比其他候选人，你觉得你的优势是什么？&quot; <a class="header-anchor" href="#相比其他候选人-你觉得你的优势是什么" aria-label="Permalink to &quot;&quot;相比其他候选人，你觉得你的优势是什么？&quot;&quot;">​</a></h3><blockquote><p>我觉得我的核心优势是**&quot;AI + 工程化&quot;的复合能力**，而不是单纯某一项强：</p><ol><li><strong>业务理解深</strong>：我不是只做 CRUD 的后端，我深入理解碳管理、LCA、CBAM 这些垂直业务，能把业务需求翻译成技术方案。比如 RAG 知识库为什么要按标准章节语义分块，是因为碳法规条款不能被截断，这种细节没有业务理解做不好。</li><li><strong>从 0 到 1 的完整经历</strong>：碳管家 AI 助手是我从选型、架构、RAG 流水线、性能优化一路做下来的，不是接手别人的系统缝缝补补。我清楚每个技术决策的 why，也知道踩过哪些坑。</li><li><strong>带队经验</strong>：我管理过 5 人团队，既写代码也做技术决策和排期，能独立扛起一块业务。</li><li><strong>结果导向</strong>：检索准确率 75%→92%、API 成本降 60%，这些是实打实的业务结果，不是 demo 指标。</li></ol><p>如果其他候选人某一环可能比我强，但能把业务理解 + 工程落地 + 团队协作 + 结果交付这四件事都做扎实的，我有信心。</p></blockquote><hr><h4 id="追问-6" tabindex="-1">追问： <a class="header-anchor" href="#追问-6" aria-label="Permalink to &quot;追问：&quot;">​</a></h4><ul><li>追问1：你说&quot;能把四件事都做扎实&quot;，那请举一例：你做过的哪个技术决策，后来证明是错的或踩了坑，你如何挽回的？ <ul><li><strong>答</strong>：早期固定长度分块就是一例——截断条款导致召回差、用户拿到半截法规。 <ul><li>发现后我做分块策略重构（章节语义分块）+ 增加重排，挽回了准确率。</li><li>教训：垂直领域不能套通用方案，要先理解业务数据的结构特征。</li></ul></li></ul></li><li>追问2：你说业务理解深、RAG 按章节分块是因为法规不能截断——那除了分块，你在 prompt 层怎么防止模型答非所问，实测效果怎样？ <ul><li><strong>答</strong>：Prompt 层三道约束：① 强制引用来源文档；② 限定&quot;只基于检索内容回答，不知道就说不知道&quot;；③ 置信度阈值低则拒答。 <ul><li>实测配合重排后，答非所问/编造来源比例明显下降（可结合埋点&quot;点踩率&quot;观察）。</li><li>输出附引用链接让用户可核实，间接约束幻觉。</li></ul></li></ul></li><li>追问3：你说结果&quot;不是 demo 指标&quot;，那碳管家 AI 助手现在真实日活和付费企业数是多少？这些数据能当场说吗？ <ul><li><strong>答</strong>：这些是内部业务数据，面试中如已签保密可披露概数，否则用区间表述。 <ul><li>可说&quot;已服务数十家付费企业、日活数百量级&quot;这类不泄密表述。</li><li>重点是展示&quot;有真实生产用户、非 demo&quot;——用留存/复访等指标佐证更稳妥。</li></ul></li></ul></li></ul>',32)])])}const d=o(a,[["render",r]]);export{p as __pageData,d as default};
